Random Encounter Info.command:
// Macro para obter informações sobre um encontro aleatório
const pack = game.packs.get("shadowdark.rollable-tables");

if (!actor || (actor.type === "PNJ")) {
	ui.notifications.warn("É impossível provocar uma reação sem um ator selecionado!");
}

// Distância inicial
const distanceTableID = pack.index.find(o => o.name === "Encontro Aleatório: Distância")._id;
const distanceTable = await pack.getDocument(distanceTableID);
const distanceResult = await distanceTable.roll();
const distance = distanceResult.results[0].text;

// Atividade
const activityTableID = pack.index.find(o => o.name === "Encontro Aleatório: Atividade")._id;
const activityTable = await pack.getDocument(activityTableID);
const activityResult = await activityTable.roll();
const activity = activityResult.results[0].text;

// Reação
const reactionTableID = pack.index.find(o => o.name === "Encontro Aleatório: Reação")._id;
const reactionTable = await pack.getDocument(reactionTableID);
const actorCha = actor.system.abilities.cha.mod;
const reactionRoll = await new Roll(`2d6 + ${actorCha}`).evaluate({async: true});
const reaction = reactionTable.getResultsForRoll(reactionRoll._total)[0].text;

// Tesouro
const treasureRoll = await new Roll("1d100").evaluate({ async: true });
const treasure = (treasureRoll._total >= 50) ? "tem tesouro" : "não tem tesouro";

const chatHtml = `
<div class="shadowdark chat-card item-card">
	<header class="card-header flexrow">
		<img src="icons/environment/people/charge.webp" />
		<h3>Encontro Aleatório !</h3>
	</header>

	<div class="card-content">
		<p>A(s) criatura(s) encontrada(s) por <em>${actor.name}</em> estão...</p>
		<p>A uma distância de : <b>${distance}</b></p>
		<p>Atualmente estão fazendo : <b>${activity}</b></p>
		<p>E a reação dele(s) é : <b>${reaction}</b></p>
		<p>Eles/elas <b>${treasure}</b></p>
	</div>
</div>
`;

const chatData = {
	user: game.user._id,
	speaker: ChatMessage.getSpeaker(),
	content: chatHtml,
	whisper: game.users.filter(u => u.isGM).map(u => u._id),
};

ChatMessage.create(chatData, {});

