SoloDark: Generate Dungeon Name.command:
// Macro para gerar um nome de masmorra aleatório para SoloDark, visível apenas para o(s) MJ(s).

const pack = game.packs.get("shadowdark.rollable-tables");

const tableNames = [
	"Nomes de masmorras: Nome 1",
	"Nomes de masmorras: Nome 2",
	"Nomes de masmorras: Nome 3",
];

const selected = [];

for (const name of tableNames) {
	const tableId = pack.index.find(o => o.name === name)._id;
	const table = await pack.getDocument(tableId);
	const result = await table.draw({displayChat: false});
	selected.push(result.results.pop().getChatText());
}

const message = `<h3>${selected.join(" ")}</h3>`;

const chatData = {
	user: game.user._id,
	speaker: ChatMessage.getSpeaker(),
	content: message,
	whisper: game.users.filter(u => u.isGM).map(u => u._id),
};

ChatMessage.create(chatData, {});

